  v_entity_key jsonb;
  v_mutation_id text;
  v_mutation_seq integer;
  v_client_timestamp_us bigint;
BEGIN
  IF p_rls_enabled THEN
    PERFORM auth.set_auth_context(COALESCE(p_user_claims, '{}'::jsonb));
  END IF;

  IF jsonb_typeof(p_batch) <> 'object' THEN
    RAISE EXCEPTION 'Batch payload must be a JSON object';
  END IF;

  IF jsonb_typeof(p_batch->'mutations') <> 'array' THEN
    RAISE EXCEPTION 'Batch payload mutations must be a JSON array';
  END IF;

  FOR mutation IN SELECT value FROM jsonb_array_elements(p_batch->'mutations')
  LOOP
    dml_sql := NULL;
    v_table := mutation->>'tableName';
    v_kind := mutation->>'kind';
    v_payload := COALESCE(mutation->'payload', '{}'::jsonb);
    v_entity_key := COALESCE(mutation->'entityKey', '{}'::jsonb);
    v_mutation_id := mutation->>'mutationId';
    v_mutation_seq := (mutation->>'mutationSeq')::integer;
    v_client_timestamp_us := NULLIF(mutation->>'clientTimestampUs', '')::bigint;

    IF FALSE THEN
      NULL;
    ELSIF v_table = 'authors' THEN
        IF v_kind = 'create' THEN
          SELECT format(
          'INSERT INTO "authors" (%s) VALUES (%s)',
          concat_ws(', ', nullif(string_agg(quote_ident(col_name), ', '), ''), '"owner_id", "modified_by", "created_at_us", "updated_at_us"'),
          concat_ws(', ', nullif(string_agg(format('($1->>%L)::%s', col_name, col_type), ', '), ''), 'auth.uid(), auth.uid(), CAST(FLOOR(EXTRACT(EPOCH FROM clock_timestamp()) * 1000000) AS BIGINT), CAST(FLOOR(EXTRACT(EPOCH FROM clock_timestamp()) * 1000000) AS BIGINT)')
        )
        INTO dml_sql
        FROM (VALUES
            ('id', 'uuid'),
            ('name', 'varchar')
        ) AS col_types(col_name, col_type)
        WHERE v_payload ? col_name;

        IF dml_sql IS NOT NULL THEN
          EXECUTE dml_sql USING v_payload;
        END IF;
        ELSIF v_kind = 'update' THEN
          SELECT format(
          'UPDATE "authors" SET %s WHERE "id" = ($2->>%L)::uuid',
          concat_ws(', ', nullif(string_agg(format('%I = ($1->>%L)::%s', col_name, col_name, col_type), ', '), ''), '"modified_by" = auth.uid(), "updated_at_us" = CAST(FLOOR(EXTRACT(EPOCH FROM clock_timestamp()) * 1000000) AS BIGINT)'),
          'id'
        )
        INTO dml_sql
        FROM (VALUES
            ('name', 'varchar'),
            ('owner_id', 'uuid'),
            ('created_at_us', 'bigint')
        ) AS col_types(col_name, col_type)
        WHERE v_payload ? col_name;

        IF dml_sql IS NOT NULL THEN
          EXECUTE dml_sql USING v_payload, v_entity_key;
        END IF;
        ELSIF v_kind = 'delete' THEN
          DELETE FROM "authors"
        WHERE "id" = (v_entity_key->>'id')::uuid;
        ELSE
          RAISE EXCEPTION 'Unsupported mutation kind "%" for table "%"', v_kind, v_table;
        END IF;
ELSIF v_table = 'todos' THEN
        IF v_kind = 'create' THEN
          SELECT format(
          'INSERT INTO "todos" (%s) VALUES (%s)',
          concat_ws(', ', nullif(string_agg(quote_ident(col_name), ', '), ''), '"owner_id", "modified_by", "created_at_us", "updated_at_us"'),
          concat_ws(', ', nullif(string_agg(format('($1->>%L)::%s', col_name, col_type), ', '), ''), 'auth.uid(), auth.uid(), CAST(FLOOR(EXTRACT(EPOCH FROM clock_timestamp()) * 1000000) AS BIGINT), CAST(FLOOR(EXTRACT(EPOCH FROM clock_timestamp()) * 1000000) AS BIGINT)')
        )
        INTO dml_sql
        FROM (VALUES
