            ('title', 'varchar'),
            ('description', 'text'),
            ('author_id', 'uuid'),
            ('status', 'varchar'),
            ('priority', 'varchar')
        ) AS col_types(col_name, col_type)
        WHERE v_payload ? col_name;

        IF dml_sql IS NOT NULL THEN
          EXECUTE dml_sql USING v_payload;
        END IF;
        ELSIF v_kind = 'update' THEN
          SELECT format(
          'UPDATE "todos" SET %s WHERE "id" = ($2->>%L)::uuid',
          concat_ws(', ', nullif(string_agg(format('%I = ($1->>%L)::%s', col_name, col_name, col_type), ', '), ''), '"modified_by" = auth.uid(), "updated_at_us" = CAST(FLOOR(EXTRACT(EPOCH FROM clock_timestamp()) * 1000000) AS BIGINT)'),
          'id'
        )
        INTO dml_sql
        FROM (VALUES
            ('title', 'varchar'),
            ('description', 'text'),
            ('author_id', 'uuid'),
            ('owner_id', 'uuid'),
            ('status', 'varchar'),
            ('priority', 'varchar'),
            ('created_at_us', 'bigint')
        ) AS col_types(col_name, col_type)
        WHERE v_payload ? col_name;

        IF dml_sql IS NOT NULL THEN
          EXECUTE dml_sql USING v_payload, v_entity_key;
        END IF;
        ELSIF v_kind = 'delete' THEN
          DELETE FROM "todos"
        WHERE "id" = (v_entity_key->>'id')::uuid;
        ELSE
          RAISE EXCEPTION 'Unsupported mutation kind "%" for table "%"', v_kind, v_table;
        END IF;
    ELSE
      RAISE EXCEPTION 'Unknown table "%" in batch mutation', v_table;
    END IF;

    IF p_log_enabled THEN
      INSERT INTO operations_log (
        source,
        backend,
        table_name,
        operation_kind,
        entity_key_json,
        payload_json,
        status,
        http_status,
        mutation_id,
        mutation_seq,
        client_timestamp_us,
        request_path,
        server_timestamp_us
      ) VALUES (
        'batch',
        'bulk-plpgsql',
        v_table,
        v_kind,
        v_entity_key,
        v_payload,
        'succeeded',
        200,
        v_mutation_id::uuid,
        v_mutation_seq,
        v_client_timestamp_us,
        p_request_path,
        CAST(FLOOR(EXTRACT(EPOCH FROM clock_timestamp()) * 1000000) AS BIGINT)
